import hashlib
import os
import base64
from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes
from cryptography.hazmat.backends import default_backend

def encrypt_data(plain_text, key):
    # Generate a random 16-byte IV
    iv = os.urandom(16)
    
    # Create a cipher object using AES algorithm in CBC mode
    cipher = Cipher(algorithms.AES(key), modes.CBC(iv), backend=default_backend())
    encryptor = cipher.encryptor()
    
    # Pad the plain_text to be a multiple of 16 bytes
    padding_length = 16 - (len(plain_text) % 16)
    padded_text = plain_text + (chr(padding_length) * padding_length)
    
    # Encrypt the padded text
    encrypted_text = encryptor.update(padded_text.encode()) + encryptor.finalize()
    
    # Return the base64 encoded IV and encrypted text
    return base64.b64encode(iv + encrypted_text).decode()

def generate_key(password, salt):
    # Derive a key from the password using PBKDF2
    return hashlib.pbkdf2_hmac('sha256', password.encode(), salt, 100000, dklen=32)

